record_types.code:
type UDC_Event (Kind : UDC_Event_Kind := None) is record
   case Kind is
      when Setup_Request =>
         Req    : Setup_Data;
         Req_EP : EP_Id;
      when Transfer_Complete =>
         EP   : EP_Addr;
         BCNT : UInt11;
      when others => null;
   end case;
end record;

